What is the output of the following C code?
#include <stdio.h>
int main() {
    int x = 5;
    int y = x++ + ++x;
    printf("%d", y);
    return 0;
}

Examine the following C++ class constructor using a member initialization list:
class Test {
    int a;
    int b;
public:
    Test(int i) : b(i), a(b + 5) {}
};
If an object is created as `Test t(10);`, what is the predictable value of `a`?

What will be the exact output of this C code snippet?
#include <stdio.h>
#include <string.h>
int main() {
    char str[] = "JECA";
    printf("%d %d", sizeof(str), strlen(str));
    return 0;
}

Predict the output of the following C macro operation:
#define SQUARE(x) x * x
int main() {
    int a = SQUARE(3 + 2);
    printf("%d", a);
    return 0;
}
